// ---------------------------------------------------------------------------
// Job error hierarchy base — InfraredJobError
// ---------------------------------------------------------------------------

/**
 * Base class for all async-job-related errors. Mirrors Python SDK's
 * `InfraredJobError`. Lets callers `catch (e: InfraredJobError)` to handle any
 * job-lifecycle failure (submit, poll, run, timeout, download) uniformly,
 * separately from non-job SDK errors.
 *
 * Existing concrete classes (JobSubmitError, JobPollError, JobFailedError,
 * JobTimeoutError, JobNotCompletedError, ResultsDownloadError) still extend
 * `InfraredError`; they additionally satisfy `instanceof InfraredJobError` via
 * the prototype chain set up below.
 */
export class InfraredJobError extends InfraredError {
  constructor(message: string, opts?: { statusCode?: number; responseBody?: string }) {
    super(message, opts)
    this.name = 'InfraredJobError'
  }
}

// Wire the existing job-error classes into the InfraredJobError hierarchy so
// `instanceof InfraredJobError` succeeds for all of them. This is a runtime
// re-parenting; the public constructor signatures of the subclasses are
// unchanged.
for (const Cls of [
  JobSubmitError,
  JobPollError,
  JobFailedError,
  JobTimeoutError,
  JobNotCompletedError,
  ResultsDownloadError,
]) {
  Object.setPrototypeOf(Cls.prototype, InfraredJobError.prototype)
}

// ---------------------------------------------------------------------------
// Area orchestration errors — port of Python SDK's tiling/types.py errors
// ---------------------------------------------------------------------------

/**
 * Raised when an area-level tiled run finishes with zero successful tiles
 * and at least one failed/skipped tile, OR when explicitly thrown by
 * `runAreaAndWait` to signal "every job in this run failed."
 *
 * Carries the partition of job IDs so callers can do recovery logic
 * (e.g. retry only `failedJobs`, ignore `skippedJobs`).
 */
export class AreaRunError extends InfraredError {
  public readonly failedJobs: readonly string[]
  public readonly skippedJobs: readonly string[]
  public readonly totalJobs: number

  constructor(
    message: string,
    opts: { failedJobs: readonly string[]; skippedJobs: readonly string[]; totalJobs: number },
  ) {
    super(message)
    this.name = 'AreaRunError'
    this.failedJobs = opts.failedJobs
    this.skippedJobs = opts.skippedJobs
    this.totalJobs = opts.totalJobs
  }
}

/**
 * Raised when `runAreaAndWait` exceeds its `areaTimeout`. Carries the
 * last observed `AreaState` so the caller can inspect partial progress
 * and decide whether to merge what's available.
 */
export class AreaTimeoutError extends InfraredError {
  // Typed as `unknown` here to avoid a circular import with tiling/types;
  // callers should narrow to `AreaState`.
  public readonly areaState: unknown

  constructor(message: string, opts: { areaState: unknown }) {
    super(message)
    this.name = 'AreaTimeoutError'
    this.areaState = opts.areaState
  }
}

/**
 * Raised when a single tile within a tiled area run fails with a
 * permanent (non-retryable) error. Wraps the underlying job error.
 */
export class TiledRunError extends InfraredError {
  public readonly tileId: string
  public readonly cause?: unknown

  constructor(message: string, opts: { tileId: string; cause?: unknown }) {
    super(message)
    this.name = 'TiledRunError'
    this.tileId = opts.tileId
    this.cause = opts.cause
  }
}

// ---------------------------------------------------------------------------
// Service-level typed errors — port of Python SDK's WeatherServiceError /
// BuildingsServiceError. Carry `operation` so callers can distinguish which
// API method raised (lookup vs filter, fetch vs merge, etc.).
// ---------------------------------------------------------------------------

/** Raised when a weather/utilities API call returns an HTTP error.
 *
 * Carries `retryAfter` parsed from the server's `Retry-After` header (seconds),
 * matching Python 0.4.9's `WeatherServiceError.retry_after` and the
 * `JobSubmitError`/`JobPollError` contract, so callers can implement an outer
 * backoff. `null` when the header was absent or unparseable. (Transparent retry
 * on retryable status is already performed by `HttpClient.fetchWithRetry`; this
 * field surfaces the hint on the final, retries-exhausted error.) */
export class WeatherServiceError extends InfraredError {
  public readonly operation: string
  public readonly retryAfter: number | null

  constructor(
    message: string,
    opts: {
      statusCode: number
      responseBody: string
      operation: string
      retryAfter?: number | null
      cause?: unknown
    },
  ) {
    super(message, {
      statusCode: opts.statusCode,
      responseBody: opts.responseBody,
      cause: opts.cause,
    })
    this.name = 'WeatherServiceError'
    this.operation = opts.operation
    this.retryAfter = opts.retryAfter ?? null
  }
}

