// ---------------------------------------------------------------------------
// Big-payload error hierarchy — port of Python SDK's
// `_internal/big_payloads/exceptions.py`. Raised by service clients that
// POST large bodies through the auto-switching `$ref` envelope flow:
// presign → S3 PUT → envelope POST. Distinct from per-service
// `*ServiceError` classes — these surface infrastructure failures, not
// domain-level API errors.
// ---------------------------------------------------------------------------

/** Base class for all big-payload-flow errors. */
export class BigPayloadError extends InfraredError {
  constructor(message: string, opts?: { statusCode?: number; responseBody?: string }) {
    super(message, opts)
    this.name = 'BigPayloadError'
  }
}

/** Raised when the gateway's `/uploads/presign` call fails or returns an
 * invalid response (non-JSON body, missing `upload-url`/`get-url`, non-HTTPS
 * scheme). */
export class BigPayloadPresignError extends BigPayloadError {
  constructor(message: string, opts?: { statusCode?: number; responseBody?: string }) {
    super(message, opts)
    this.name = 'BigPayloadPresignError'
  }
}

/** Raised when the S3 PUT to the presigned URL fails. Common root causes:
 * `Content-Length` mismatch (S3 returns `SignatureDoesNotMatch`), or transient
 * 5xx exhausted the bounded retry budget. */
export class BigPayloadUploadError extends BigPayloadError {
  constructor(message: string, opts?: { statusCode?: number; responseBody?: string }) {
    super(message, opts)
    this.name = 'BigPayloadUploadError'
  }
}

/**
 * Raised when the receiving service returns a typed `REF_*` error after the
 * envelope POST. `code` carries the gateway/lambda-models contract code
 * (`REF_NOT_FOUND`, `REF_TOO_LARGE`, `REF_INVALID_ENVELOPE`, `REF_FETCH_TIMEOUT`,
 * `REF_HOST_NOT_ALLOWED`, `REF_CONTENT_TYPE_REJECTED`, `REF_DECODE_FAILED`,
 * `REF_EXPIRED`). Callers can dispatch on `code` without parsing the message.
 */
export class BigPayloadFetchError extends BigPayloadError {
  public readonly code: string

  constructor(
    code: string,
    message: string,
    opts?: { statusCode?: number; responseBody?: string },
  ) {
    super(message, opts)
    this.name = 'BigPayloadFetchError'
    this.code = code
  }
}

/** Raised when the `REF_EXPIRED` retry budget is consumed without success.
 * Always carries `code="REF_EXPIRED"` so existing handlers that dispatch on
 * `BigPayloadFetchError.code` keep working. */
export class RefExpiredRetryExhausted extends BigPayloadFetchError {
  constructor(message: string, opts?: { statusCode?: number; responseBody?: string }) {
    super('REF_EXPIRED', message, opts)
    this.name = 'RefExpiredRetryExhausted'
  }
}
